// Input expected on $json:
//   brand_id, contact_email, stage, opportunity_stage (alias for stage)
// Returns: { allowed: bool, reason: string, assigned_channels: string[] }

const input        = $input.first().json;
const recentAssets = $('Collision Guard — Check Recent Sends').first().json;

const contactEmail    = input.contact_email ?? '';
const stage           = input.stage ?? input.opportunity_stage ?? 'post_purchase';

// ---------------------------------------------------------------
// COLLISION CHECK
// Check if this contact's email appears in any target_segment of
// an executed campaign asset in the last 7 days.
// ---------------------------------------------------------------
const assets = Array.isArray(recentAssets) ? recentAssets : [];
const alreadySent = assets.some(a => {
  const seg = a.opportunities?.target_segment ?? '';
  return seg.includes(contactEmail);
});

if (alreadySent) {
  return [{ json: { allowed: false, reason: 'Contact received a campaign in the last 7 days', assigned_channels: [] } }];
}

// ---------------------------------------------------------------
// CHANNEL ASSIGNMENT RULE (deterministic — not AI-decided)
// ---------------------------------------------------------------
let assigned_channels = [];

if (stage === 'pre_purchase') {
  // abandoned cart / welcome — email + sms
  assigned_channels = ['email', 'sms'];
} else if (stage === 'first_purchase') {
  // nurture — email only
  assigned_channels = ['email'];
} else if (stage === 'post_purchase') {
  const segment = (input.target_segment ?? '').toLowerCase();
  if (segment.includes('at-risk') || segment.includes('lapsed') ||
      segment.includes('inactive') || segment.includes('win_back') ||
      segment.includes('win back')) {
    // Highest urgency — whatsapp + email
    assigned_channels = ['whatsapp', 'email'];
  } else {
    // Repeat / repurchase window — email primary, sms secondary
    assigned_channels = ['email', 'sms'];
  }
}

return [{ json: { allowed: true, reason: 'OK', assigned_channels } }];
